{"code":"const merged = github.list_pull_requests({ state: "merged" });
const withLinear = merged.filter(pr => pr.closes_linear);

const results = withLinear.map(pr => {
  const title = "Verify: " + pr.title;
  github.create_issue({ repo: "acme/web", title: title });
  return { pr: pr.number, repo: pr.repo, linear: pr.closes_linear, opened_title: title };
});

results.length"}
